  private autoCompleteFilter(field: any, value: string): any[] {
    const filterValue = (value || '').toString().toLowerCase();
    return (field.options || []).filter((opt: any) => {
      const label =
        field.name === 'Cargo' ? opt?.type : field.name === 'ToCurrency' || field.name === 'FromCurrency' ? opt : opt?.name;

      return label?.toLowerCase().includes(filterValue);
    });
  }

